var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"……종신계약?","JPN":"……終身契約？","ENG":"A Lifetime Contract?","TWN":"……終身契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"어째서 내게 기사의 맹세를 요구하는 거지? 현자여.","JPN":"どうして私に騎士の誓いを求める？　賢者よ。","ENG":"Why do you request my oath, Sage?","TWN":"賢者，你為何要求我以騎士之名立誓呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"아무리 제국이 멸망했다 하더라도 나는 마르티네즈 가문에 속한 몸.","JPN":"いくら帝国が滅亡したとはいえ、私はマルチネス家に属した身。","ENG":"Even if the Empire fell, I am still a Martinez.","TWN":"就算帝國已經滅亡，但我還是馬汀尼茲家族的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"내게는 전하의 충실한 검이 되어, 가문이 저지른 불명예를 씻어내야 할 책무가 있다.","JPN":"私には殿下の忠実な剣となり、一族が犯した不名誉を晴らす責務がある。","ENG":"I have the duty to become the loyal sword of His Highness and atone the sin that my family committed.","TWN":"我有責任要對殿下效忠，以洗清家族犯下的污名。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"다시 말해, 두 개의 깃발을 받드는 일은 결코 용납되지 않는다는 말이지.","JPN":"つまり、二つの旗を掲げることは、決して許されるものではないということだ。","ENG":"Which means, I cannot serve two banners at once.","TWN":"意思就是，我絕對無法接受同時效忠兩個人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"그렇군. 늑대라…….","JPN":"そうか。狼か……","ENG":"I see. The Wolf...","TWN":"原來如此，狼嗎……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"확실히 이번 세계에서의 늑대는 그다지 믿음직스러워 보이지는 않다만……","JPN":"確かにこの世界での狼はあまり頼もしいとは思えないが……","ENG":"She certainly is not the same reliable Wolf from the other world she was in...","TWN":"在這次世界的狼確實感覺沒那麼可靠……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"누구보다 자유로웠던 그녀는…… 나와 친구가 되어준 유일한 이였지.","JPN":"誰よりも自由だった彼女は……私と友だちになってくれた唯一の人だった。","ENG":"She had such a free spirit... She was the only one who was willing to befriend me.","TWN":"卻比任何人都自由……因此也只有她願意和我做朋友。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"비록 나는 그녀처럼 자유로울 수는 없겠지만.","JPN":"私は彼女のように自由にはなれないが。","ENG":"I will never be free like her.","TWN":"雖然我無法像她那般自由，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"이 세계에서 그녀가 어떻게 지내는지는 관심이 있다.","JPN":"この世界で、彼女がどのように過ごしているかは興味がある。","ENG":"But I am interested to see how she is faring in this world.","TWN":"但我很好奇她在這個世界是怎麼生活的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"……좋다. 현자여.","JPN":"……よし。賢者よ。","ENG":"Very well, Sage.","TWN":"……好吧，賢者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"당분간 그대에게 힘을 빌려주지.","JPN":"しばしの間、お前に力を貸すとしよう。","ENG":"I will help you for a while.","TWN":"我就暫時助你一臂之力吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_SCHOOL_NULL","text":{"KOREA":"그렇지만 그것이 곧 그대에게 충성을 바친다는 말은 아니야.","JPN":"しかし、それがお前に忠誠を誓うという意味ではない。","ENG":"But that doesn’t mean that I will be loyal to you.","TWN":"但這可不是我會效忠於你的意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_SCHOOL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};